mapper.select:
select date_format(s.snapshot_month, '%Y-%m') as month, coalesce(nullif(a.investment_type, ''), '未设置') as name, sum(s.amount) as value from monthly_snapshots s join accounts a on a.id = s.account_id where s.snapshot_month between #{startMonth} and #{endMonth}
and a.asset_category = #{assetCategory}
group by s.snapshot_month, coalesce(nullif(a.investment_type, ''), '未设置') order by s.snapshot_month, coalesce(nullif(a.investment_type, ''), '未设置')

select date_format(s.snapshot_month, '%Y-%m') as month, coalesce(a.risk_level, '未设置') as name, sum(s.amount) as value from monthly_snapshots s join accounts a on a.id = s.account_id where s.snapshot_month between #{startMonth} and #{endMonth}
and a.asset_category = #{assetCategory}
group by s.snapshot_month, coalesce(a.risk_level, '未设置') order by s.snapshot_month, coalesce(a.risk_level, '未设置')

select coalesce(nullif(a.investment_type, ''), '未设置') as name,
       sum(s.amount) as value,
       round(sum(s.amount) / nullif(total.total_amount, 0) * 100, 2) as percent
from monthly_snapshots s
join accounts a on a.id = s.account_id
join (
    select sum(s2.amount) as total_amount
    from monthly_snapshots s2
    join accounts a2 on a2.id = s2.account_id
    where s2.snapshot_month = #{snapshotMonth}

        and a2.asset_category = #{assetCategory}

) total
where s.snapshot_month = #{snapshotMonth}

    and a.asset_category = #{assetCategory}

group by coalesce(nullif(a.investment_type, ''), '未设置'), total.total_amount
order by value desc

select coalesce(a.risk_level, '未设置') as name,
       sum(s.amount) as value,
       round(sum(s.amount) / nullif(total.total_amount, 0) * 100, 2) as percent
from monthly_snapshots s
join accounts a on a.id = s.account_id
join (
    select sum(s2.amount) as total_amount
    from monthly_snapshots s2
    join accounts a2 on a2.id = s2.account_id
    where s2.snapshot_month = #{snapshotMonth}

        and a2.asset_category = #{assetCategory}

) total
where s.snapshot_month = #{snapshotMonth}

    and a.asset_category = #{assetCategory}

group by coalesce(a.risk_level, '未设置'), total.total_amount
order by value desc
